window.T13NE.Die.getDice=function(boon){
	return window.T13NE.Die.findDice("Boon",boon);
}
window.T13NE.Die.findDice = function(arg,needle){
	var retvar=[];
	var lastdie=[];
	lastdie[arg]=0; 
	window.T13NE.Dice.forEach(function(die, index) {
		if (die[arg]<=needle){
			if (die[arg]>lastdie[arg]){
				lastdie=die;
			}
		}
		if (die[arg]==needle){
			if(arg=="Dice_Id"){
				return die;
			}else{
				retvar[retvar.length]=die;
			}
		}
	});
	if (retvar.length>0){return retvar;}else{return lastdie;}
};
window.T13NE.Die.RollDice= function (die){
	//console.log("RollDice ",die);
	var number=0;
	var mod=0;
	var d=1;
	var roll=0;
	if (typeof die == "number"){
		die = window.T13NE.Dice[die]["Die"];
	}
	die = die.toLowerCase();
	 number = parseInt(die.substring(0,die.indexOf("d")));
	 //console.log("number",number);
	if (die.indexOf("+")!==-1){
		d=parseInt(die.substring(die.indexOf("d")+1,die.indexOf("+")));
		mod=parseInt(die.substring(die.indexOf("+"), die.length));

	}else if(die.indexOf("-")!==-1){
		//console.log(die.substring(die.indexOf("d"), die.indexOf("-")));
		d=parseInt(die.substring(die.indexOf("d")+1, die.indexOf("-")));
		mod=parseInt(die.substring(die.indexOf("-"), die.length));
	}else{
		d=die.substring(die.indexOf("d")+1, die.length);
		mod=0;
	}
	//console.log("d",d);
	//console.log("mod",mod);
	roll=mod;
	for (var i =0; i<number;i++){
		roll+=window.T13NE.RNG(1,d,0);
		console.log("rolling...",roll);
	}
	//console.log("rolled",roll);
	return roll;
}
window.T13NE.Die.RollDieButton = class extends window.T13NE.Component{
	constructor(props){
		super(props);
		this.onClick=this.onClick.bind(this);
		this.state={"result":"unrolled"};
	}
	onClick=(ev) =>{
		console.log("clicking", ev.target);

		this.setState({"result":window.T13NE.Die.RollDice(ev.target.getAttribute("data-dice"))});
	}
	render(){
		return window.T13NE.CE("span", {className:this.props.className+"-span t13ne-dice-container","key":Date.now().toString(36) +"-"+ Math.random().toString(36).substr(2, 6)+"-"+ Math.random().toString(36).substr(2, 6)},window.T13NE.CE("button", {className:this.props.className+"-button t13ne-roll-dice", "onClick":this.onClick, "type":"button","data-dice":this.props["data-dice"]}, "Roll"),
			this.state.result!=="unrolled"?window.T13NE.CE("output", {className:this.props.className+"-span-output t13ne-result"},"Score: (" + this.state.result +") ["+window.T13NE.Boon.getBoonReduced(this.state.result,false)+"]"):null);
	}
}
window.T13NE.Die.DisplayDie= function (props){
	var die=window.T13NE.Dice[(Number(props["data-die"])-1)];
	var css="t13ne-die";
	if (die.Main){css+=" t13ne-main-die";}
	if (window.T13NE.Contains(die.Die, "-")){css += " t13ne-lesser-die";}
	if (window.T13NE.Contains(die.Die, "+")){css += " t13ne-greater-die";}
	return window.T13NE.CE("div",{className:props.className+"-div t13ne-dice", "data-die":props["data-die"],"key":Date.now().toString(36) +"-"+ Math.random().toString(36).substr(2, 6)+"-"+ Math.random().toString(36).substr(2, 6)}, 
		window.T13NE.CE("span",{className:props.className+"-div-span "+css}, die.Die),
		window.T13NE.CE("span", {className:props.className+"-div-span t13ne-average"}, parseInt(die["Minimum_Score"])+"..."+die["Average_Score"]+"..."+parseInt(die["Maximum_Score"])), 
		window.T13NE.CE(window.T13NE.Die.RollDieButton,{className:props.className+"-div-button t13ne-roll-dice", "data-minimum":die["Minimum_Score"], "data-maximum":die["Maximum_Score"], "data-dice":die.Die, }));
}
window.T13NE.Die.DisplayDice = function (props){
	var dicer=window.T13NE.Die.findDice("Boon", props["data-boon"]);
	var ret=[];
	dicer.forEach( function(thisdie, index) {
		ret[ret.length]= window.T13NE.CE(window.T13NE.Die.DisplayDie,{"data-die":thisdie["Dice_Id"],"key":Date.now().toString(36) +"-"+ Math.random().toString(36).substr(2, 6)+"-"+ Math.random().toString(36).substr(2, 6)})
	});
	return ret;
}
